		for(int i = 0 ; i < Y ; i++)

			for(int j = 0 ; j < X ; j++){

				char c; scanf(" %c",&c);

				if(c == 'S'){

					sx = j , sy = i;

				}else if( c == 'G'){

					gx = j , gy = i;

				}else if( c != '.'){

					c = c - '1';

					x[c][sz[c]] = j;

					y[c][sz[c]++] = i;			

				}

			}

		priority_queue<NODE> Q;

		for(int i = 0 ; i < 5 ; i++){

			Q.push(NODE(sx,sy,(i+1)%5,0,i));

		}

		tr1::unordered_map< int , int > memo[5][5];



		while(Q.size()){



			NODE q = Q.top(); Q.pop();





