	int x,y,z,cost,fc;

	NODE(int x,int y,int z,int cost,int fc):

	x(x) , y(y) , z(z) , cost(cost) , fc(fc) {}

};

bool operator < (const NODE &a,const NODE &b){

	return a.cost != b.cost ? a.cost > b.cost : a.fc > b.fc;

}



int x[5][1000];

int y[5][1000];

int sz[5];

int main(){

	while(cin >> X >> Y && X){

		int sx,sy,gx,gy;

		for(int i = 0 ; i < 5 ; i++) sz[i]=0;



		for(int i = 0 ; i < Y ; i++)

			for(int j = 0 ; j < X ; j++){

				char c; scanf(" %c",&c);

				if(c == 'S'){

					sx = j , sy = i;

				}else if( c == 'G'){

					gx = j , gy = i;

				}else if( c != '.'){

					c = c - '1';

					x[c][sz[c]] = j;

					y[c][sz[c]++] = i;			

				}

			}

