int memo[5][5][1111];



int solve(int k, int t, int q){



  if(k == 4) return abs(p[t][q].F-gx) + abs(p[t][q].S-gy);

  if(memo[k][t][q]) return memo[k][t][q];



  int ans = INF, d = (t+1)%5, c;

